// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const configGet = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/create-trail/result`);
  const configBody = await configGet.json();

  if (!configBody.TrailArn) {
    console.log("CloudTrail creation failed!");
    throw new Error("CloudTrail creation failed!");
  }

  console.log("CloudTrail enabled successfully");
  console.log("Trail ARN: " + configBody.TrailArn);
  console.log("S3 Bucket: " + configBody.S3BucketName);

  return configBody;
}
